  test("side_effects_catch".fail) {
    assertCompresses(
      input = """function f() {
            function g() {
                try {
                    throw 0;
                } catch (e) {
                    console.log("PASS");
                }
            }
            g();
        }
        f()""".stripMargin.trim,
      expected = """function f() {
            (function() {
                try {
                    throw 0;
                } catch (e) {
                    console.log("PASS");
                }
            })();
        }
        f()""".stripMargin.trim,
